  ('fire-eq-tech-moex-02810', 'fire-eq-tech', 'fire-eq-tech-moex-098-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '電信機械室如採局部放射之乾粉滅火設備設計時，依體積法所核算出之滅火藥劑量，應再乘以多少比例？', '["0.5", "0.7", "1.1", "1.2"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "8a14d92dbadf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
