  ('fire-eq-tech-moex-02815', 'fire-eq-tech', 'fire-eq-tech-moex-098-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '二氧化碳滅火系統之全區放射防護區域對放射之滅火藥劑採自然排放時，設有面向外氣且為防護區域自 樓地板面起高度2/3以下，能開啟之開口部大小，應為多少？', '["占防護區域樓地板面積10%以上", "占防護區域圍壁面積10%以上", "占防護區域樓地板面積20%以上", "占防護區域圍壁面積20%以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "8a14d92dbadf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02816', 'fire-eq-tech', 'fire-eq-tech-moex-098-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '依據「各類場所消防安全設備設置標準」之規定，二氧化碳滅火設備之藥劑放射規定，下列何者正確？', '["電信機械室採全區放射時，藥劑需於7分鐘內放射完畢", "存放一般物品之無人倉庫採全區放射時，藥劑需於1分鐘內放射完畢", "局部放射方式藥劑需於3.5分鐘內放射完畢", "移動式放射方式每一具瞄子每分鐘之藥劑放射量應在90公斤以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "8a14d92dbadf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-02817', 'fire-eq-tech', 'fire-eq-tech-moex-098-a98764b7', 'sub-fire-eq-tech-01', NULL, 'single_choice', '二氧化碳滅火設備使用氣體啟動者，下列敘述何者正確？', '["內容積應有0.6公升以上", "所儲存之二氧化碳重量在1公斤以上，充填比在1.5以上", "不得兼供防護之區選擇閥使用", "啟動用氣體容器要能耐25 MPa之壓力"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:25+00:00", "source_pdf_sha1": "8a14d92dbadf", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "4001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "水與化學系統消防安全設備概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
